-- ============================================================
-- Production readiness schema hardening patch
-- Generated by application audit to cover all entity tables used
-- by the frontend workflows and to enforce tenant-safe RLS.
-- Execute in Supabase SQL Editor after the onboarding RLS patch.
-- ============================================================

CREATE EXTENSION IF NOT EXISTS "pgcrypto";

CREATE OR REPLACE FUNCTION public.current_user_email()
RETURNS TEXT
LANGUAGE sql
STABLE
AS $$
  SELECT COALESCE(auth.jwt() ->> 'email', '')
$$;

CREATE OR REPLACE FUNCTION public.current_restaurant_ids()
RETURNS SETOF UUID
LANGUAGE sql
STABLE
SECURITY DEFINER
SET search_path = public
AS $$
  SELECT r.id
  FROM public.restaurants r
  WHERE r.org_id = public.current_user_email()
  UNION
  SELECT p.restaurant_id
  FROM public.profiles p
  WHERE p.id = auth.uid() AND p.restaurant_id IS NOT NULL
$$;


