ALTER TABLE announcements ENABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS "announcements: owner all" ON announcements;
CREATE POLICY "announcements: owner all" ON announcements
  FOR ALL
  USING (
    created_by = public.current_user_email()
    OR restaurant_id IN (SELECT id::text FROM public.current_restaurant_ids())
    OR branch = (SELECT branch FROM public.profiles WHERE id = auth.uid())
    OR branch_key = (SELECT branch FROM public.profiles WHERE id = auth.uid())
  )
  WITH CHECK (
    created_by = public.current_user_email()
    OR restaurant_id IN (SELECT id::text FROM public.current_restaurant_ids())
    OR branch = (SELECT branch FROM public.profiles WHERE id = auth.uid())
    OR branch_key = (SELECT branch FROM public.profiles WHERE id = auth.uid())
    OR auth.uid() IS NOT NULL
  );
DROP TRIGGER IF EXISTS trg_announcements_updated_date ON announcements;
CREATE TRIGGER trg_announcements_updated_date
  BEFORE UPDATE ON announcements
  FOR EACH ROW EXECUTE FUNCTION update_updated_date();

