ALTER TABLE driver_debts ENABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS "driver_debts: owner all" ON driver_debts;
CREATE POLICY "driver_debts: owner all" ON driver_debts
  FOR ALL
  USING (
    created_by = public.current_user_email()
    OR restaurant_id IN (SELECT id::text FROM public.current_restaurant_ids())
    OR branch = (SELECT branch FROM public.profiles WHERE id = auth.uid())
    OR branch_key = (SELECT branch FROM public.profiles WHERE id = auth.uid())
  )
  WITH CHECK (
    created_by = public.current_user_email()
    OR restaurant_id IN (SELECT id::text FROM public.current_restaurant_ids())
    OR branch = (SELECT branch FROM public.profiles WHERE id = auth.uid())
    OR branch_key = (SELECT branch FROM public.profiles WHERE id = auth.uid())
    OR auth.uid() IS NOT NULL
  );
DROP TRIGGER IF EXISTS trg_driver_debts_updated_date ON driver_debts;
CREATE TRIGGER trg_driver_debts_updated_date
  BEFORE UPDATE ON driver_debts
  FOR EACH ROW EXECUTE FUNCTION update_updated_date();

