ALTER TABLE network_accounts ENABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS "network_accounts: owner all" ON network_accounts;
CREATE POLICY "network_accounts: owner all" ON network_accounts
  FOR ALL
  USING (
    created_by = public.current_user_email()
    OR restaurant_id IN (SELECT id::text FROM public.current_restaurant_ids())
    OR branch = (SELECT branch FROM public.profiles WHERE id = auth.uid())
    OR branch_key = (SELECT branch FROM public.profiles WHERE id = auth.uid())
  )
  WITH CHECK (
    created_by = public.current_user_email()
    OR restaurant_id IN (SELECT id::text FROM public.current_restaurant_ids())
    OR branch = (SELECT branch FROM public.profiles WHERE id = auth.uid())
    OR branch_key = (SELECT branch FROM public.profiles WHERE id = auth.uid())
    OR auth.uid() IS NOT NULL
  );
