-- Existing tables that were present but lacked workflow RLS policies.
DROP POLICY IF EXISTS "Branches: owner manage all" ON branches;
CREATE POLICY "Branches: owner manage all" ON branches
  FOR ALL
  USING (restaurant_id IN (SELECT id FROM public.current_restaurant_ids()) OR created_by = public.current_user_email())
  WITH CHECK (restaurant_id IN (SELECT id FROM public.current_restaurant_ids()) OR created_by = public.current_user_email());

DROP POLICY IF EXISTS "Categories: owner manage all" ON categories;
CREATE POLICY "Categories: owner manage all" ON categories
  FOR ALL
  USING (restaurant_id IN (SELECT id FROM public.current_restaurant_ids()) OR created_by = public.current_user_email())
  WITH CHECK (restaurant_id IN (SELECT id FROM public.current_restaurant_ids()) OR created_by = public.current_user_email());

DROP POLICY IF EXISTS "Order items: owner manage all" ON order_items;
CREATE POLICY "Order items: owner manage all" ON order_items
  FOR ALL
  USING (order_id IN (SELECT id FROM orders WHERE restaurant_id IN (SELECT id FROM public.current_restaurant_ids())))
  WITH CHECK (order_id IN (SELECT id FROM orders WHERE restaurant_id IN (SELECT id FROM public.current_restaurant_ids())));
